mapper.select:
SELECT RNUM, 0 AS CHK, ItemID, Identifier, ItemTypeCode, Path, Site, SiteCode, DocLevCode, DocLev, DocFieldCode, DocField, DocTypeCode, DocType, KeyWord, ItemName, ClassCode, OwnerTeamName, Name, LastUpdated, CreationTime, Version, CSVersion, SiteCode, ItemTypeName, Status, StatusName, CSStatus, CSStatusName, PItemID, AuthorID, L1Name, L1ItemID, L2Name, L2ItemID, ChargeSite FROM ( SELECT Row_Number() OVER(ORDER BY TI.CreationTime DESC) AS RNUM, TI.ItemID, TI.Identifier AS Identifier, TI.ItemTypeCode AS ItemTypeCode, ISNULL(TIPT.Path, '') AS Path, ISNULL(TIA.PlainText, '') AS ItemName, AggData.Site AS Site, AggData.SiteCode AS SiteCode, ISNULL(TIA3.LovCode,'') AS DocLevCode, ISNULL(LOV2.Value,'')AS DocLev, ISNULL(TIA5.LovCode,'') AS DocFieldCode, ISNULL(LOV4.Value,'') AS DocField, ISNULL(TIA6.LovCode,'') AS DocTypeCode, ISNULL(LOV5.Value,'') AS DocType, ISNULL(TIA10.PlainText,'')AS KeyWord, TI.ClassCode, TOT.Name AS OwnerTeamName, CASE WHEN #{languageID} In (#{languageID},2052,1041) THEN TM.Name ELSE ISNULL(TM.NameEN,TM.Name) END AS Name, TI.Version, TI.Status, TSD.Name AS StatusName, TCS.Status as CSStatus, TCD.Name AS CSStatusName, TID.Name AS ItemTypeName, CONVERT(nvarchar(10), TCSM.ApproveDate, 120) AS LastUpdated, ISNULL(CONVERT(nvarchar(10), TCSN.ApproveDate, 120),CONVERT(nvarchar(10), TI.CreationTime,120)) AS CreationTime, TCS.Version AS CSVersion, ISNULL(ST.FromItemID, '') AS PItemID, TI.AuthorID, L1.PlainText as L1Name, L1.itemID as L1ItemID, L2.PlainText as L2Name, L2.itemID as L2ItemID, ISNULL(LOV1.Value,'') AS ChargeSite FROM XBOLTADM.TB_ITEM TI INNER JOIN ( SELECT DIM.ItemID, STUFF(( SELECT ', ' + DTXT2.Name FROM XBOLTADM.TB_ITEM_DIM DIM2 INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID INNER JOIN XBOLTADM.TB_DIM_VALUE_TXT DTXT2 ON DTXT2.DimValueID = DIM2.DimValueID AND DTXT2.LanguageID = #{languageID} WHERE DIM2.ItemID = DIM.ItemID ORDER BY TDV2.SortNum FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS Site, STUFF(( SELECT ', ' + TDV2.DimValueID FROM XBOLTADM.TB_ITEM_DIM DIM2 INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID WHERE DIM2.ItemID = DIM.ItemID ORDER BY TDV2.SortNum FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS SiteCode FROM XBOLTADM.TB_ITEM_DIM DIM GROUP BY DIM.ItemID ) AggData ON AggData.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID ON TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 ON TI.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'ZAT01010' AND TIA2.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'ZAT01020' AND TIA3.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 ON TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'ZAT01040' AND TIA5.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 ON TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'ZAT01060' AND TIA6.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 ON TI.ItemID = TIA10.ItemID AND TIA10.AttrTypeCode = 'AT01007' AND TIA10.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TW_ITEM_HIER TIH ON TI.ItemID = TIH.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR L1 ON TIH.L1ItemID = L1.ItemID AND L1.AttrTypeCode = 'AT00001' AND L1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR L2 ON TIH.L2ItemID = L2.ItemID AND L2.AttrTypeCode = 'AT00001' AND L2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV1 ON LOV1.LovCode = TIA2.PlainText And LOV1.AttrTypeCode = 'ZAT01010' AND LOV1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV2 ON LOV2.LovCode = TIA3.LovCode AND LOV2.AttrTypeCode = 'ZAT01020' AND LOV2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV4 ON LOV4.LovCode = TIA5.LovCode AND LOV4.AttrTypeCode = 'ZAT01040' AND LOV4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV5 ON LOV5.LovCode = TIA6.LovCode AND LOV5.AttrTypeCode = 'ZAT01060' AND LOV5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TI.CurChangeSet = TCS.ChangeSetID LEFT OUTER JOIN XBOLTADM.TB_ITEM ST ON TI.ItemID = ST.ToItemID AND ST.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TW_ITEM_PATH_TXT TIPT ON TIPT.ItemID = TI.ItemID AND TIPT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TCD ON TCS.Status = TCD.TypeCode AND TCD.LanguageID = #{languageID} AND TCD.Category = 'CNGSTS' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSN ON TI.ItemID = TCSN.ItemID AND TCSN.ChangeType = 'NEW' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSM ON TI.ItemID = TCSM.ItemID AND TCSM.ChangeType = 'MOD' AND TI.ReleaseNo = TCSM.ChangeSetID WHERE (TI.Deleted != 1 or (TI.Deleted = 1 AND TI.Status = 'REL') ) AND TI.ClassCode in (${defClassList})
AND ( TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in ('SKO1') )
AND TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in (${siteCode}) )
)
AND TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in (${siteCode}) )
And TCS.Status = #{csStatus}
AND TCSN.ApproveDate BETWEEN #{SC_STR_DT1} AND #{SC_END_DT1}
AND TCSM.ApproveDate BETWEEN #{SC_STR_DT2} AND #{SC_END_DT2}
) A WHERE 1 = 1
And L1ItemID = #{L1ItemID}
And L2ItemID = #{L2ItemID}
And (Identifier like N'%'+#{searchValue}+'%' OR itemName like N'%'+#{searchValue}+'%')
AND ( itemName like N'%'+#{totalInfo}+'%' OR Keyword like N'%'+#{totalInfo}+'%' )
And Identifier like N'%'+#{identifier}+'%'
And itemName like N'%'+#{itemName}+'%'
And Status = #{status}
And Status = #{ownerTeamID}
And Name like N'%'+#{authorName}+'%'
And OwnerTeamName like N'%'+#{ownerTeamName}+'%'
And DocTypeCode = #{ZAT01060}
And DocFieldCode = #{ZAT01040}
And DocLevCode = #{ZAT01020}
And Keyword like N'%'+#{keyWord}+'%'

SELECT COUNT(*) AS value, TATL.Value AS label
FROM XBOLTADM.TW_PROCESS TP
INNER JOIN XBOLTADM.TB_ITEM_ATTR IA ON TP.ItemID=IA.ItemID AND IA.AttrTypeCode='ZAT01060' AND IA.LanguageID=#{defaultLang}
INNER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL ON IA.LovCode = TATL.LovCode AND TATL.AttrTypeCode = 'ZAT01060' AND TATL.LanguageID = #{sessionCurrLangType}
WHERE TP.ItemClassCode=#{ClassCode}
GROUP BY TATL.Value

SELECT DISTINCT Row_Number() OVER(ORDER BY TI.CreationTime DESC) AS RNUM, 0 AS CHK, '' AS Link, TI.ItemID, TI.Identifier AS Identifier, TI.ItemTypeCode AS ItemTypeCode, ISNULL(TIPT.Path, '') AS Path, AggData.Site AS Site, AggData.SiteCode AS SiteCode, ISNULL(TIA.PlainText, '') AS ItemName, ISNULL(TIA2.LovCode, '') AS ZAT03260Code, ISNULL(TATL1.Value, '') AS ZAT03260, ISNULL(TIA_AGG.ZAT04003Code, '') AS ZAT04003Code, ISNULL(TIA_AGG.ZAT04003, '') AS ZAT04003, ISNULL(TIA_AGG.ZAT04006Code, '') AS ZAT04006Code, ISNULL(TIA_AGG.ZAT04006, '') AS ZAT04006, TI.ClassCode, TOT.Name AS OwnerTeamName, CONVERT(nvarchar(10), TCS.CompletionDT, 120) AS CompletionDT, TCS.Description as Description, CASE WHEN #{languageID} In (#{languageID},2052,1041) THEN TM.Name ELSE ISNULL(TM.NameEN,TM.Name) END AS Name, TCS.Version, TI.Status, TSD.Name AS StatusName, TCS.Status as CSStatus, TCD.Name AS CSStatusName, TID.Name AS ItemTypeName, TI.AuthorID, TIA3.PlainText AS KeyWord, TCS0.AuthorName AS firstAuthorName, CONVERT(nvarchar(10), TCS0.CompletionDT, 120) AS firstCompletionDT, ISNULL(ST.FromItemID, '') AS PItemID FROM XBOLTADM.TB_ITEM TI INNER JOIN ( SELECT DIM.ItemID, STRING_AGG(DTXT.Name, ', ') AS Site, STRING_AGG(DTXT.DimValueID, ', ') AS SiteCode FROM XBOLTADM.TB_ITEM_DIM DIM INNER JOIN XBOLTADM.TB_DIM_VALUE_TXT DTXT ON DTXT.DimValueID = DIM.DimValueID and DTXT.LanguageID = #{languageID} GROUP BY DIM.ItemID ) AggData ON AggData.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TI.CurChangeSet = TCS.ChangeSetID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TCD ON TCS.Status = TCD.TypeCode AND TCD.LanguageID = #{languageID} AND TCD.Category = 'CNGSTS' LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID ON TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 ON TI.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'ZAT03260' AND TIA2.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL1 ON TIA2.LovCode = TATL1.LovCode AND TATL1.AttrTypeCode = 'ZAT03260' AND TATL1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'AT01007' AND TIA3.LanguageID = #{LanguageID} LEFT JOIN ( SELECT ATTR.ItemID, STRING_AGG(CASE WHEN ATTR.AttrTypeCode = 'ZAT04003' THEN ATTR.LovCode END, ',') AS ZAT04003Code, STRING_AGG(CASE WHEN ATTR.AttrTypeCode = 'ZAT04003' THEN ISNULL(VAL.Value, '') END, ',') AS ZAT04003, STRING_AGG(CASE WHEN ATTR.AttrTypeCode = 'ZAT04006' THEN ATTR.LovCode END, ',') AS ZAT04006Code, STRING_AGG(CASE WHEN ATTR.AttrTypeCode = 'ZAT04006' THEN ISNULL(VAL.Value, '') END, ',') AS ZAT04006 FROM XBOLTADM.TB_ITEM_ATTR ATTR LEFT JOIN XBOLTADM.TB_ATTR_TYPE_LOV VAL ON ATTR.LovCode = VAL.LovCode AND ATTR.AttrTypeCode = VAL.AttrTypeCode AND VAL.LanguageID = #{languageID} WHERE ATTR.AttrTypeCode IN ('ZAT04003', 'ZAT04006') AND ATTR.LanguageID = #{languageID} GROUP BY ATTR.ItemID ) TIA_AGG ON TI.ItemID = TIA_AGG.ItemID LEFT OUTER JOIN XBOLTADM.TW_ITEM_PATH_TXT TIPT ON TIPT.ItemID = TI.ItemID AND TIPT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM ST ON TI.ItemID = ST.ToItemID AND ST.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR L2 ON ST.FromItemID = L2.ItemID AND L2.AttrTypeCode = 'AT00001' AND L2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_DIM TIDM ON AggData.SiteCode = TIDM.DimValueID and TI.ItemID = TIDM.ItemID LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS0 ON TI.ItemID = TCS0.itemID and TCS0.Version = '0' WHERE (TI.Deleted != 1 ) AND TI.ClassCode in (${defClassList})
AND TIDM.DimValueID = (select PlainText from XBOLTADM.TB_ITEM_ATTR where AttrTypeCode = 'ZAT01010' and ItemID = #{L2ItemID})
And TI.Identifier = #{ZAT09006}
AND ( TIA.PlainText like N'%'+#{totalInfo}+'%' OR TIA3.PlainText like N'%'+#{totalInfo}+'%' )
And TIA.PlainText like N'%'+#{itemName}+'%'
And TIA3.PlainText like N'%'+#{keyWord}+'%'
AND CASE WHEN #{languageID} IN (#{languageID},2052,1041) THEN TM.Name ELSE ISNULL(TM.NameEN, TM.Name) END LIKE N'%'+#{authorName}+'%'
AND TI.ItemID IN (Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in (#{ZAT01010}))
And TIA2.LovCode = #{ZAT03260}
AND (
TIA_AGG.ZAT04003Code LIKE '%${item}%' OR TIA_AGG.ZAT04003 LIKE '%${item}%'
)
AND (
TIA_AGG.ZAT04006Code LIKE '%${item}%' OR TIA_AGG.ZAT04006 LIKE '%${item}%'
)
AND ISNULL(TCSN.ApproveDate, TI.CreationTime) BETWEEN #{SC_STR_DT1} AND #{SC_END_DT1}
